mapper.sql:
FROM vehicle v
JOIN model m ON m.model_id = v.model_id
JOIN brand b ON b.brand_id = m.brand_id


        AND v.vehicle_vin LIKE CONCAT(#{query.vehicleVin}, '%')


        AND b.brand_id = #{query.brandId}


        AND m.model_id = #{query.modelId}


        AND v.current_status = #{query.currentStatus}


        AND v.color = #{query.color}


        AND v.inventory_in_date >= #{query.inventoryInDateStart}


        AND v.inventory_in_date <= #{query.inventoryInDateEnd}


        AND v.manufacture_date >= #{query.manufactureDateStart}


        AND v.manufacture_date <= #{query.manufactureDateEnd}

mapper.update:
UPDATE vehicle
SET current_status = 'IN_INVENTORY',
    inventory_in_date = #{inventoryInDate}
WHERE vehicle_vin = #{vehicleVin}
  AND current_status = 'IN_TRANSIT'

mapper.select:
SELECT COUNT(1)
FROM staff
WHERE staff_id = #{staffId}

SELECT inv.model_id, m.brand_id, inv.brand_name, inv.model_name, inv.model_year, inv.trim_name, m.safety_stock_threshold, inv.in_inventory_count, inv.locked_count, inv.in_transit_count, (m.safety_stock_threshold - inv.in_inventory_count) AS shortage_count FROM v_inventory_summary inv JOIN model m ON m.model_id = inv.model_id
(m.safety_stock_threshold - inv.in_inventory_count) > 0
AND m.brand_id = #{query.brandId}
AND inv.model_id = #{query.modelId}
ORDER BY shortage_count DESC, inv.brand_name, inv.model_name
